#include<bits/stdc++.h>using namespace std;int q,n,ans=0;string s,t;int main(){	cin>>q;	while(q--){		cin>>s>>t;		int flag=0;		for(int k=0;k<s.size();k++){			for(int i=1;i<=s.size()-k;i++){				int j=t.size()-i-1;				string h="";				h=h+s[k];				for(int l=1,x=k+1;l<=i;l++,x++) h=h+s[x];				for(int l=1,x=k+i-1;l<=j;l++,x--) h=h+s[x];				int f=0;				for(int l=0;l<t.size();l++){					if(t[l]!=h[l]){						f=1;break;					}				}				if(f==0&&flag==0){					cout<<"YES"<<endl;					flag=1;				}			}		}		if(flag==0) cout<<"NO"<<endl;	}		return 0;}